// GetAgentSessionsGraphQL implements ddxgraphql.StateProvider.
// Reads pointer-only monthly session shards from every registered project.
func (s *ServerState) GetAgentSessionsGraphQL(startedAfter, startedBefore *time.Time) []*ddxgraphql.AgentSession {
	projects := s.GetProjects(false)
	var out []*ddxgraphql.AgentSession
	for _, proj := range projects {
		sessions := readProjectSessions(proj, startedAfter, startedBefore)
		out = append(out, sessions...)
	}
	// Newest first.
	sort.Slice(out, func(i, j int) bool {
		ti, _ := time.Parse(time.RFC3339, out[i].StartedAt)
		tj, _ := time.Parse(time.RFC3339, out[j].StartedAt)
		return ti.After(tj)
	})
	return out
}

// GetAgentSessionGraphQL implements ddxgraphql.StateProvider.
func (s *ServerState) GetAgentSessionGraphQL(id string) (*ddxgraphql.AgentSession, bool) {
	projects := s.GetProjects(false)
	for _, proj := range projects {
		logDir := agent.SessionLogDirForWorkDir(proj.Path)
		entry, ok, err := agent.FindSessionIndex(logDir, id)
		if err != nil || !ok {
			continue
		}
		sess := agentSessionFromIndex(proj.ID, entry)
		bodies := agent.LoadSessionBodies(proj.Path, entry)
		if bodies.Prompt != "" {
			sess.Prompt = &bodies.Prompt
		}
		if bodies.Response != "" {
			sess.Response = &bodies.Response
		}
		if bodies.Stderr != "" {
			sess.Stderr = &bodies.Stderr
		}
		return sess, true
	}
	return nil, false
}

// GetSessionsCostSummaryGraphQL implements ddxgraphql.StateProvider.
// It reads exactly the requested project's monthly session shards.
func (s *ServerState) GetSessionsCostSummaryGraphQL(projectID string, since, until *time.Time) *ddxgraphql.SessionsCostSummary {
	proj, ok := s.GetProjectByID(projectID)
	if !ok {
		return &ddxgraphql.SessionsCostSummary{}
	}
	logDir := agent.SessionLogDirForWorkDir(proj.Path)
	entries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{
		StartedAfter:  since,
		StartedBefore: until,
	})
	if err != nil {
		return &ddxgraphql.SessionsCostSummary{}
	}
	summary := &ddxgraphql.SessionsCostSummary{}
	var localTokens int
	for _, e := range entries {
		mode := e.BillingMode
		if mode == "" {
			mode = agent.BillingModeFor(e.Harness, e.Surface, e.BaseURL)
		}
		switch mode {
		case agent.BillingModePaid:
			summary.CashUsd += e.CostUSD
		case agent.BillingModeSubscription:
			summary.SubscriptionEquivUsd += e.CostUSD

let defaultRoute = $state<DefaultRouteStatus | null>(null);
let loading = $state(true);
let error = $state<string | null>(null);
let firstPaintAt = $state<number | null>(null);

// Per-row model snapshots loaded on demand when a row is expanded.
const modelsByKey = $state<Record<string, ProviderModelsResult>>({});
const modelsLoading = $state<Record<string, boolean>>({});
const modelsError = $state<Record<string, string>>({});
const expanded = $state<Record<string, boolean>>({});

// Threshold above which the inline list is truncated and a drilldown
// link to the per-provider detail page is shown.
const MODEL_LIST_INLINE_LIMIT = 10;

function rowKey(row: ProviderStatus): string {
	return row.kind + '|' + row.name;
}

let modelsClient: ReturnType<typeof createClient> | null = null;

async function loadModels(row: ProviderStatus): Promise<void> {
	const key = rowKey(row);
	if (!modelsClient) modelsClient = createClient();
	modelsLoading[key] = true;
	delete modelsError[key];
	try {
		const res = await modelsClient.request<{
			providerModels: ProviderModelsResult | null;
		}>(PROVIDER_MODELS_QUERY, { name: row.name, kind: row.kind });
		if (res.providerModels) modelsByKey[key] = res.providerModels;
	} catch (e) {
		modelsError[key] = e instanceof Error ? e.message : String(e);
	} finally {
		modelsLoading[key] = false;
	}
}

async function refreshModels(row: ProviderStatus): Promise<void> {
	const key = rowKey(row);
	if (!modelsClient) modelsClient = createClient();
	modelsLoading[key] = true;
	delete modelsError[key];
	try {
		const res = await modelsClient.request<{
			refreshProviderModels: ProviderModelsResult;
		}>(REFRESH_PROVIDER_MODELS_MUTATION, { name: row.name, kind: row.kind });
		modelsByKey[key] = res.refreshProviderModels;
		expanded[key] = true;
	} catch (e) {
		modelsError[key] = e instanceof Error ? e.message : String(e);
	} finally {
		modelsLoading[key] = false;
	}
}

function toggleExpanded(row: ProviderStatus): void {
	const key = rowKey(row);
	const next = !expanded[key];
	expanded[key] = next;
	if (next && !modelsByKey[key] && !modelsLoading[key]) {
		void loadModels(row);
	}
}

$effect(() => {
	if (!loading && firstPaintAt === null) {
		firstPaintAt = Date.now();
	}
});

// Polling interval for live row patching after first paint. Chosen to be
// short enough that probe results surface within the 5s AC budget but long
// enough to not hammer the server. AC 1: rows patch within 5s of probe
// completion — since the resolver returns cached rows updated asynchronously
// by refreshProviderStatuses, polling here is sufficient to reflect them.
const POLL_INTERVAL_MS = 2500;
let pollTimer: ReturnType<typeof setInterval> | null = null;

async function refresh(client: ReturnType<typeof createClient>) {
	const result = await client.request<{
		providerStatuses: ProviderStatus[];
		harnessStatuses: ProviderStatus[];
	}>(PROVIDER_STATUSES_QUERY);
	rows = [...(result.providerStatuses ?? []), ...(result.harnessStatuses ?? [])];
}

onMount(() => {
	const client = createClient();
	// First paint: provider + harness rows. defaultRouteStatus fires in
	// parallel via a separate query so a slow route-resolver can't delay
	// the table from rendering. AC 1: table interactive within 500ms.
	refresh(client)
		.catch((e) => {
			error = e instanceof Error ? e.message : String(e);
		})
		.finally(() => {
			loading = false;
		});

	client
		.request<{ defaultRouteStatus: DefaultRouteStatus | null }>(DEFAULT_ROUTE_QUERY)
		.then((res) => {
			defaultRoute = res.defaultRouteStatus ?? null;
		})
		.catch(() => {
			// Non-fatal: the default-route widget is informational only.
		});

	pollTimer = setInterval(() => {
		refresh(client).catch(() => {
			// Polling errors are transient; keep the last-known rows.
		});
	}, POLL_INTERVAL_MS);

	return () => {
		if (pollTimer != null) {
			clearInterval(pollTimer);
			pollTimer = null;
		}
	};
});

function statusClass(row: ProviderStatus): string {
	if (row.reachable) return 'text-status-closed';
	const lower = row.status.toLowerCase();
	if (
		lower.includes('connected') ||
		lower === 'available' ||
		lower.includes('api key configured')
	) {
		return 'text-status-closed';
	}
	if (
		lower.includes('cooldown') ||
		lower.includes('unreachable') ||
		lower.includes('error') ||
		lower === 'unavailable' ||
		lower.startsWith('unavailable')
	) {
		return 'text-status-failed';
	}
	return 'text-status-in-progress';
}

function formatTokens(n: number | null | undefined): string {
	if (n == null) return '—';
	if (n < 1000) return `${n}`;
	if (n < 1_000_000) return `${(n / 1000).toFixed(1)}k`;
	return `${(n / 1_000_000).toFixed(2)}M`;
}

function utilizationPct(usage: ProviderUsage | null, quota: ProviderQuota | null): number | null {
	if (!usage || !quota) return null;
	if (quota.ceilingTokens == null || quota.ceilingTokens <= 0) return null;
	const window = quota.ceilingWindowSeconds ?? 60;
	// Choose the usage field that matches the ceiling window (1h / 24h).
	const usedTokens = window <= 3600 ? usage.tokensUsedLastHour : usage.tokensUsedLast24h;
	if (usedTokens == null) return null;
	return Math.min(100, Math.round((usedTokens * 100) / quota.ceilingTokens));
}

function sparklineMax(values: number[]): number {
	let m = 0;
	for (const v of values) if (v > m) m = v;
	return m === 0 ? 1 : m;
}

function sparkBarHeight(value: number, max: number): string {
	const pct = Math.round((value * 100) / max);
	return `${Math.max(2, pct)}%`;
}

function detailHref(row: ProviderStatus): string {
	const nodeId = $page.params.nodeId;
	return `/nodes/${nodeId}/providers/${encodeURIComponent(row.name)}`;
}

// Section toggle (Availability / Performance) is URL-driven via the Story 8
// chip query-param schema (`?section=availability|performance`). Default
// section is availability so the existing URL keeps working.
let section = $derived<SectionKey>(
	($page.url.searchParams.get('section') as SectionKey | null) === 'performance'
		? 'performance'
		: 'availability'
);
let perfWindow = $derived<WindowKey>(
	(($page.url.searchParams.get('window') ?? 'W7D') as WindowKey)
);

function setSection(next: SectionKey): void {
	const params = new URLSearchParams($page.url.searchParams);
	if (next === 'availability') params.delete('section');
	else params.set('section', next);
	const search = params.toString();
	goto(search ? `?${search}` : $page.url.pathname, { replaceState: false });
}

function setWindow(next: WindowKey): void {
	const params = new URLSearchParams($page.url.searchParams);
	params.set('section', 'performance');

package graphql

import (
	"context"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	ddxexec "github.com/DocumentDrivenDX/ddx/internal/exec"
)

// NodeStateSnapshot holds node identity data for resolver consumption.
type NodeStateSnapshot struct {
	ID        string
	Name      string
	StartedAt time.Time
	LastSeen  time.Time
}

// BeadDependencySnapshot holds dependency data for resolver consumption.
type BeadDependencySnapshot struct {
	IssueID     string
	DependsOnID string
	Type        string
	CreatedAt   string
	CreatedBy   string
	Metadata    string
}

// BeadSnapshot holds bead data for resolver consumption.
type BeadSnapshot struct {
	ProjectID    string
	ID           string
	Title        string
	Status       string
	Priority     int
	IssueType    string
	Owner        string
	CreatedAt    time.Time
	CreatedBy    string
	UpdatedAt    time.Time
	Labels       []string
	Parent       string
	Description  string
	Acceptance   string
	Notes        string
	Dependencies []BeadDependencySnapshot
}

// StateProvider is the minimal interface the node/projects resolvers need.
type StateProvider interface {
	GetNodeSnapshot() NodeStateSnapshot
	GetProjectSnapshots(includeUnreachable bool) []*Project
	GetProjectSnapshotByID(id string) (*Project, bool)
	GetBeadSnapshots(status, label, projectID, search string) []BeadSnapshot
	// GetBeadSnapshotsForProject returns snapshots for a single registered
	// project without iterating any other projects' stores. Implementations
	// MUST open only the named project's bead store. The resolver for
	// Query.beadsByProject uses this path to avoid the N-project scan that
	// backs the cross-project GetBeadSnapshots call (ddx-9ce6842a).
	GetBeadSnapshotsForProject(projectID, status, label, search string) []BeadSnapshot
	GetBeadSnapshot(id string) (*BeadSnapshot, bool)

	// Worker queries
	GetWorkersGraphQL(projectID string) []*Worker
	GetWorkerGraphQL(id string) (*Worker, bool)
	GetWorkerLogGraphQL(id string) *WorkerLog
	GetWorkerProgressGraphQL(id string) []*PhaseTransition
	GetWorkerPromptGraphQL(id string) string

	// AgentSession queries
	GetAgentSessionsGraphQL(startedAfter, startedBefore *time.Time) []*AgentSession
	GetAgentSessionGraphQL(id string) (*AgentSession, bool)
	GetSessionsCostSummaryGraphQL(projectID string, since, until *time.Time) *SessionsCostSummary

	// Exec queries
	GetExecDefinitionsGraphQL(artifactID string) []*ExecutionDefinition
	GetExecDefinitionGraphQL(id string) (*ExecutionDefinition, bool)
	GetExecRunsGraphQL(artifactID, definitionID string) []*ExecutionRun
	GetExecRunGraphQL(id string) (*ExecutionRun, bool)
	GetExecRunLogGraphQL(runID string) *ExecutionRunLog

	// Coordinator queries
	GetCoordinatorsGraphQL() []*CoordinatorMetricsEntry
	GetCoordinatorMetricsByProjectGraphQL(projectRoot string) *CoordinatorMetrics
}

// Node is the resolver for the node(id: ID!) field (Relay lookup by global ID).
//
// LAYER 3 of the GraphQL multi-project leak fix (ddx-5ae050dc): Bead and
// ExecutionRun lookups are scoped to the request's WorkingDir (via
// WithWorkingDir/r.workingDir(ctx)) so two projects with overlapping bead IDs
// or run IDs do not leak across one another. Unknown ID prefixes return
// (nil, nil).
func (r *queryResolver) Node(ctx context.Context, id string) (Node, error) {
	if strings.HasPrefix(id, "node-") {
		snap := r.State.GetNodeSnapshot()
		if snap.ID != id {
			return nil, nil
		}
		return nodeInfoFromSnapshot(snap), nil
	}
	if strings.HasPrefix(id, "proj-") {
		proj, ok := r.State.GetProjectSnapshotByID(id)
		if !ok {
			return nil, nil
		}
		return proj, nil
	}
	if strings.HasPrefix(id, "bead-") {
		beadID := strings.TrimPrefix(id, "bead-")
		if beadID == "" {
			return nil, nil
		}
		wd := r.workingDir(ctx)
		if wd == "" {
			return nil, nil
		}
		store := bead.NewStore(filepath.Join(wd, ".ddx"))
		b, err := store.Get(beadID)
		if err != nil || b == nil {
			return nil, nil
		}
		snap := BeadSnapshot{
			ID:          b.ID,
			Title:       b.Title,
			Status:      b.Status,
			Priority:    b.Priority,
			IssueType:   b.IssueType,
			Owner:       b.Owner,
			CreatedAt:   b.CreatedAt,
			CreatedBy:   b.CreatedBy,
			UpdatedAt:   b.UpdatedAt,
			Labels:      b.Labels,
			Parent:      b.Parent,
			Description: b.Description,
			Acceptance:  b.Acceptance,
			Notes:       b.Notes,
		}
		for _, d := range b.Dependencies {
			snap.Dependencies = append(snap.Dependencies, BeadDependencySnapshot{
				IssueID:     d.IssueID,
				DependsOnID: d.DependsOnID,
				Type:        d.Type,
				CreatedAt:   d.CreatedAt,
				CreatedBy:   d.CreatedBy,
				Metadata:    d.Metadata,
			})
		}
		return beadFromSnapshot(snap), nil
	}
	if strings.HasPrefix(id, "exec-") {
		wd := r.workingDir(ctx)
		if wd == "" {
			return nil, nil
		}
		store := ddxexec.NewStore(wd)
		runs, err := store.History("", "")
		if err != nil {
			return nil, nil
		}
		for _, rec := range runs {
			if rec.RunID == id {
				return execRunNodeFromRecord(rec), nil
			}
		}
		return nil, nil
	}
	return nil, nil
}

// execRunNodeFromRecord builds a minimal ExecutionRun GraphQL value from a
// ddxexec.RunRecord for Node(id) resolution. Mirrors execRunFromRecord in the
// server package but is local to graphql to avoid an import cycle.
func execRunNodeFromRecord(rec ddxexec.RunRecord) *ExecutionRun {
	r := &ExecutionRun{
		ID:           rec.RunID,
		DefinitionID: rec.DefinitionID,
		ArtifactIds:  rec.ArtifactIDs,
		StartedAt:    rec.StartedAt.UTC().Format(time.RFC3339),
		FinishedAt:   rec.FinishedAt.UTC().Format(time.RFC3339),
		Status:       rec.Status,
		ExitCode:     rec.ExitCode,
	}
	if rec.MergeBlocking {
		b := true
		r.MergeBlocking = &b
	}
	if rec.AgentSessionID != "" {
		s := rec.AgentSessionID
		r.AgentSessionID = &s
	}
	return r
