 98	func AppendSessionIndex(logDir string, entry SessionIndexEntry, now time.Time) error {
 99		if logDir == "" {
100			return nil
101		}
102		if now.IsZero() {
103			now = time.Now().UTC()
104		}
105		if entry.ID == "" {
106			entry.ID = genSessionID()
107		}
108		if entry.StartedAt.IsZero() {
109			entry.StartedAt = now.UTC()
110		}
111		if entry.EndedAt.IsZero() && entry.DurationMS > 0 {
112			entry.EndedAt = entry.StartedAt.Add(time.Duration(entry.DurationMS) * time.Millisecond).UTC()
113		}
114		if entry.Outcome == "" {
115			if entry.ExitCode == 0 && entry.Detail == "" {
116				entry.Outcome = "success"
117			} else {
118				entry.Outcome = "failure"
119			}
120		}
121		if entry.BillingMode == "" {
122			entry.BillingMode = billingModeFor(entry.Harness, entry.Surface, entry.BaseURL)
123		}
124		if !ValidateBillingMode(entry.BillingMode) {
125			return fmt.Errorf("invalid billingMode %q", entry.BillingMode)
126		}
127		if err := os.MkdirAll(SessionIndexDir(logDir), 0o755); err != nil {
128			return err
129		}
130		data, err := json.Marshal(entry)
131		if err != nil {
132			return err
133		}
134		path := SessionIndexShardPath(logDir, now.UTC())
135		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
136		if err != nil {
137			return err
138		}
139		defer f.Close()
140		_, err = fmt.Fprintf(f, "%s\n", data)
141		return err
142	}
