 54	// GetBeadSnapshots implements ddxgraphql.StateProvider.
 55	//
 56	// When projectID is non-empty this delegates to GetBeadSnapshotsForProject so
 57	// the resolver path opens exactly one project's store; a scoped query never
 58	// pays the N-project scan cost (ddx-9ce6842a Part 2 step 1). When projectID is
 59	// empty every registered project is scanned — that is still O(projects) by
 60	// necessity, but each project's bead.Store receives a pushed-down filter so
 61	// non-matching beads are never materialized as BeadSnapshot values.
 62	func (s *ServerState) GetBeadSnapshots(status, label, projectID, search string) []ddxgraphql.BeadSnapshot {
 63		if projectID != "" {
 64			return s.GetBeadSnapshotsForProject(projectID, status, label, search)
 65		}
 66		projects := s.GetProjects()
 67		pred := beadFilterPredicate(status, label, search)
 68		var result []ddxgraphql.BeadSnapshot
 69		for _, proj := range projects {
 70			result = append(result, s.beadSnapshotsForProjectEntry(proj, pred)...)
 71		}
 72		return result
 73	}
 74	
 75	// GetBeadSnapshotsForProject implements ddxgraphql.StateProvider. It opens
 76	// exactly one project's bead store — iteration over other projects is not
 77	// performed for any reason, so the cross-project loop cost is avoided for the
 78	// common per-project bead list.
 79	func (s *ServerState) GetBeadSnapshotsForProject(projectID, status, label, search string) []ddxgraphql.BeadSnapshot {
 80		if projectID == "" {
 81			return nil
 82		}
 83		proj, ok := s.GetProjectByID(projectID)
 84		if !ok {
 85			return nil
 86		}
 87		pred := beadFilterPredicate(status, label, search)
 88		return s.beadSnapshotsForProjectEntry(proj, pred)
 89	}
 90	
 91	// beadStoreOpenHook is a test-only hook: when non-nil, every call to
 92	// beadSnapshotsForProjectEntry invokes it with the project path it is about
 93	// to open. Tests use this to assert that the scoped path opens exactly one
 94	// project's store (ddx-9ce6842a AC §3).
 95	var beadStoreOpenHook func(projectPath string)
 96	
 97	// beadSnapshotsForProjectEntry reads the single project's bead store, applies
 98	// the (possibly nil) predicate at the store layer (filter pushdown), and
 99	// returns GraphQL snapshots for the matching beads. Callers are responsible
100	// for deciding which projects to pass through — this helper never touches any
101	// other project's state.
102	func (s *ServerState) beadSnapshotsForProjectEntry(proj ProjectEntry, pred func(bead.Bead) bool) []ddxgraphql.BeadSnapshot {
103		if beadStoreOpenHook != nil {
104			beadStoreOpenHook(proj.Path)
105		}
106		store := bead.NewStore(filepath.Join(proj.Path, ".ddx"))
107		beads, err := store.ReadAllFiltered(pred)
108		if err != nil {
109			return nil
110		}
111		out := make([]ddxgraphql.BeadSnapshot, 0, len(beads))
112		for _, b := range beads {
113			s.rememberBeadLocation(b.ID, proj)
114			out = append(out, beadSnapshotFromStoreBead(proj.ID, b))
115		}
116		return out
117	}
118	
119	// beadFilterPredicate returns a predicate suitable for bead.Store.ReadAllFiltered
120	// that applies status/label/search filters. A nil return means "match all".
121	func beadFilterPredicate(status, label, search string) func(bead.Bead) bool {
122		if status == "" && label == "" && search == "" {
123			return nil
124		}
125		q := strings.ToLower(search)
126		return func(b bead.Bead) bool {
127			if status != "" && b.Status != status {
128				return false
129			}
130			if label != "" && !containsString(b.Labels, label) {
131				return false
132			}
133			if q != "" {
134				if !strings.Contains(strings.ToLower(b.ID), q) && !strings.Contains(strings.ToLower(b.Title), q) {
135					return false
136				}
137			}
138			return true
139		}
140	}
