178		s.beadIndexMu.RLock()
179		defer s.beadIndexMu.RUnlock()
180		if s.beadIndex == nil {
181			return beadIndexEntry{}, false
182		}
183		loc, ok := s.beadIndex[id]
184		return loc, ok
185	}
