203	func beadSnapshotFromStoreBead(projectID string, b bead.Bead) ddxgraphql.BeadSnapshot {
204		snap := ddxgraphql.BeadSnapshot{
205			ProjectID:   projectID,
206			ID:          b.ID,
207			Title:       b.Title,
208			Status:      b.Status,
209			Priority:    b.Priority,
210			IssueType:   b.IssueType,
211			Owner:       b.Owner,
212			CreatedAt:   b.CreatedAt,
213			CreatedBy:   b.CreatedBy,
214			UpdatedAt:   b.UpdatedAt,
215			Labels:      b.Labels,
216			Parent:      b.Parent,
217			Description: b.Description,
218			Acceptance:  b.Acceptance,
219			Notes:       b.Notes,
220		}
221		for _, d := range b.Dependencies {
222			snap.Dependencies = append(snap.Dependencies, ddxgraphql.BeadDependencySnapshot{
223				IssueID:     d.IssueID,
224				DependsOnID: d.DependsOnID,
225				Type:        d.Type,
