129			let sum = 0;
130			for (const p of series) sum += p.tokens;
131			return sum;
132		}
133	
134		function totalRequests(series: TrendPoint[]): number {
135			let sum = 0;
136			for (const p of series) sum += p.requests;
137			return sum;
138		}
139	
140		function formatN(n: number): string {
141			if (n < 1000) return `${n}`;
142			if (n < 1_000_000) return `${(n / 1000).toFixed(1)}k`;
143			return `${(n / 1_000_000).toFixed(2)}M`;
144		}
145	
146		function formatStartedAt(value: string): string {
147			const date = new Date(value);
148			if (Number.isNaN(date.getTime())) return value;
149			return date.toLocaleString([], {
150				month: 'short',
151				day: 'numeric',
152				hour: '2-digit',
153				minute: '2-digit'
154			});
155		}
156	
157		function formatDuration(ms: number): string {
158			if (ms < 1000) return `${ms}ms`;
159			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`;
160			const minutes = Math.floor(ms / 60_000);
161			const seconds = Math.floor((ms % 60_000) / 1000);
162			return `${minutes}m ${seconds}s`;
163		}
