175			};
176			const q = body.query;
177			if (q.includes('AgentMetricsByProvider')) {
178				await route.fulfill({
179					status: 200,
180					contentType: 'application/json',
181					body: JSON.stringify({
182						data: {
183							agentMetrics: {
184								window: body.variables?.window ?? 'W7D',
185								groupBy: 'PROVIDER',
186								revision: 'rev-test',
187								rows: AGENT_METRICS_ROWS
188							}
189						}
190					})
191				});
192				return;
193			}
194			if (q.includes('NodeInfo')) {
195				await route.fulfill({
196					status: 200,
197					contentType: 'application/json',
198					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
199				});
200				return;
201			}
202			if (q.includes('ProviderStatuses')) {
203				await route.fulfill({
204					status: 200,
205					contentType: 'application/json',
206					body: JSON.stringify({
207						data: {
208							providerStatuses: ENDPOINT_ROWS,
209							harnessStatuses: HARNESS_ROWS
210						}
211					})
212				});
213				return;
214			}
215			if (q.includes('DefaultRouteStatus')) {
216				await route.fulfill({
217					status: 200,
218					contentType: 'application/json',
219					body: JSON.stringify({ data: { defaultRouteStatus: null } })
220				});
221				return;
222			}
223			if (q.includes('ProviderTrend')) {
224				const windowDays = body.variables?.windowDays ?? 7;
225				await route.fulfill({
226					status: 200,
227					contentType: 'application/json',
228					body: JSON.stringify({
229						data: {
230							providerTrend: windowDays === 7 ? TREND_WITH_CEILING : TREND_30D
231						}
232					})
233				});
234				return;
235			}
236			if (q.includes('ProviderRecentUsage')) {
237				await route.fulfill({
238					status: 200,
239					contentType: 'application/json',
240					body: JSON.stringify({
241						data: {
